commit 74791746d6cdbaadbd11b6906a8d26afca7fcd36
Author: Aral Roca Gomez <aral-rg@hotmail.com>
Date:   Tue Mar 17 10:29:35 2026 +0100

    fix(app-router): update translation instance when locale changes (#1256)

    The useMemo hook in createTranslation was only depending on defaultNS. In App Router, during soft navigation where components might not unmount, the translation function 't' was remaining stale with the previous language. Adding 'lang' to the dependency array ensures 't' is regenerated when the locale changes.

diff --git a/src/createTranslation.tsx b/src/createTranslation.tsx
index 1197f57..4f6976f 100644
--- a/src/createTranslation.tsx
+++ b/src/createTranslation.tsx
@@ -1,24 +1,24 @@
 import { useMemo } from 'react'
 import isServer from './isServer'
 import transCore from './transCore'
 import wrapTWithDefaultNs from './wrapTWithDefaultNs'

 // Only for App directory
 export default function createTranslation(defaultNS?: string) {
   const { lang, namespaces, config } = globalThis.__NEXT_TRANSLATE__ ?? {}
   const localesToIgnore = config.localesToIgnore || ['default']
   const ignoreLang = !lang || localesToIgnore.includes(lang)
   const getT = () => {
     const t = transCore({
       config,
       allNamespaces: namespaces,
       pluralRules: new Intl.PluralRules(ignoreLang ? undefined : lang),
       lang,
     })

     return wrapTWithDefaultNs(t, defaultNS)
   }

-  const t = isServer() ? getT() : useMemo(getT, [defaultNS])
+  const t = isServer() ? getT() : useMemo(getT, [defaultNS, lang])
   return { t, lang }
 }
